<template>
	<view class="page">
		<u-navbar title="优惠券"></u-navbar>
		<view>
			<u-tabs-swiper ref="uTabs" :list="tabList" :current="current" @change="tabsChange" :is-scroll="false"
				active-color="rgba(255, 33, 33, 1)" :bold="false" swiperWidth="750" bar-width="80"></u-tabs-swiper>
		</view>
		<swiper style="flex:1;" :current="swiperCurrent" @transition="transition" @animationfinish="animationfinish">
			<swiper-item class="swiper-item" v-for="(item, index) in tabList" :key="index">
				<scroll-view scroll-y style="height: 100%;width: 100%;" @scrolltolower="onreachBottom">
					<view class="coupon-list">
						<view class="coupon-item" v-for="(coupon_item,coupon_index) in list[index]" :key="coupon_index">
							<view class="coupon-wrap">
								<view class="left">
									<view class="price-num">
										<text class="symbol">￥</text>
										<text class="num">1</text>
									</view>
								</view>
								<view class="middle">
									<view class="condition-txt">满{{coupon_item.use_min_price}}去使用</view>
									<view class="limit-time">{{coupon_item._start_end_time}}</view>
								</view>
								<view class="right">
									<view class="use-status no-use" v-if="coupon_item.status === 0"
										@click="goCouponPage(coupon_item)">使用</view>
									<view class="use-status used" v-else-if="coupon_item.status === 1">已使用</view>
									<view class="use-status expire" v-else-if="coupon_item.status === 2">已过期</view>
								</view>
							</view>
						</view>
						<u-loadmore :status="swiperLoading" :margin-top="20" :margin-bottom="30" @loadmore="lower" />
					</view>
				</scroll-view>
			</swiper-item>
		</swiper>
	</view>
</template>

<script>
	import _ from 'lodash'

	export default {
		data() {
			return {
				tabList: [{
					name: '未使用'
				}, {
					name: '已使用'
				}, {
					name: '已过期'
				}],
				current: 0,
				swiperCurrent: 0,

				queryForm: {
					type: '',
					status: 0,
					page: 1,
					limit: 10,
				},
				page: [1, 1, 1],
				list: [
					[],
					[],
					[]
				],
				total: [0, 0, 0],
				loading: ['loadmore', 'loadmore', 'loadmore'],
			};
		},
		computed: {
			swiperLoading: {
				get() {
					return this.loading[this.swiperCurrent]
				},
				set(val) {
					this.$set(this.loading, this.swiperCurrent, val)
				}
			},
			swpierPage: {
				get() {
					return this.page[this.swiperCurrent]
				},
				set(val) {
					this.$set(this.page, this.swiperCurrent, val)
				}
			},
			swpierTotal: {
				get() {
					return this.total[this.swiperCurrent]
				},
				set(val) {
					this.$set(this.total, this.swiperCurrent, val)
				}
			},
			swpierList: {
				get() {
					return this.list[this.swiperCurrent]
				},
				set(val) {
					this.$set(this.list, this.swiperCurrent, val)
				}
			},
		},
		onLoad() {
			this.fetchAllData()
		},
		methods: {
			tabsChange(index) {
				this.swiperCurrent = index
			},
			transition(e) {
				let dx = e.detail.dx
				this.$refs.uTabs.setDx(dx)
			},
			animationfinish(e) {
				let current = e.detail.current
				this.$refs.uTabs.setFinishCurrent(current)
				this.swiperCurrent = current
				this.current = current
				this.queryForm.status = current
			},
			onreachBottom() {
				this.lower()
			},
			async fetchAllData() {
				const data = await this.$u.api.getMyAllCouponList()
				let list = []
				let total = []
				let loading = []

				data.forEach((item, index) => {
					total.push(item.total)
					list.push(item.list)
					if (item.list.length < this.queryForm.limit) {
						loading[index] = 'nomore'
					} else {
						loading[index] = 'loadmore'
					}
				})
				this.list = list
				this.total = total
				this.loading = loading
			},
			async fetchData() {
				if (this.swiperLoading == 'nomore')
					return
				this.swiperLoading = 'loading'

				const query_form = _.cloneDeep(this.queryForm)
				query_form.page = this.swpierPage

				const {
					list,
					total
				} = await this.$u.api.getMyCouponList(query_form)
				this.swpierTotal = total
				if (list.length) {
					this.swpierList = this.swpierList.concat(list)
				}
				if (list.length < this.queryForm.limit) {
					this.swiperLoading = 'nomore'
				} else {
					this.swiperLoading = 'loadmore'
				}
			},
			reloadData() {
				this.swpierPage = 1
				this.swiperLoading = 'loadmore'
				this.swpierList = []
				this.fetchData()
			},
			// 加载下一页
			lower() {
				if (this.swiperLoading == 'nomore')
					return
				this.swpierPage++
				this.fetchData()
			},
			// 根据优惠券适用类型跳页面
			goCouponPage(row) {
				this.$util.on('/pages/index/index')
			},
		}
	};
</script>
<style lang="scss" scoped scoped>
	.page {
		background-color: #fff;
		display: flex;
		flex-direction: column;
		height: calc(100vh - var(--window-top));
		width: 100%;
	}

	.coupon-list {
		display: flex;
		flex-direction: column;
		gap: 20rpx;
		padding-top: 20rpx;

		.coupon-item {
			padding: 0 20rpx;

			.coupon-wrap {
				background-color: #FDF0E8;
				border-radius: 20rpx;
				display: flex;
				height: 166rpx;
				align-items: center;


				.left {
					width: 166rpx;
					display: flex;
					flex-direction: column;
					align-items: center;
					justify-content: center;
					position: relative;



					.price-num {
						font-size: 48rpx;
						font-weight: 700;
						color: #ff504b;

						.symbol {
							font-size: 24rpx;
						}
					}

					.discount-num {
						font-size: 48rpx;
						font-weight: 700;
						color: #ff504b;

						.symbol {
							font-size: 24rpx;

						}
					}
				}

				.middle {
					flex: 1;
					color: #DE3C37;

					.condition-txt {
						font-size: 34rpx;
						font-weight: 700;
					}

					.limit-time {
						margin-top: 10rpx;
						font-size: 26rpx;
					}
				}

				.right {
					position: relative;
					height: 100%;
					display: flex;
					align-items: center;
					justify-content: center;
					width: 200rpx;

					&::before {
						content: '';
						height: 60%;
						border: 1px dashed #B6818A;
						position: absolute;
						top: 50%;
						left: 0;
						transform: translateY(-50%);
					}

					.use-status {
						font-size: 32rpx;
						font-weight: 700;
					}

					.no-use {
						color: #E23C2D;
					}

					.used {
						color: gray;
					}

					.expire {
						color: #e5e5e5;
					}
				}
			}
		}
	}
</style>